css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { min-height: 100vh; display: flex; align-items: center; justify-content: center; background: radial-gradient(ellipse at top, #2e2705 0%, #070b18 60%); padding: 24px; }
.card { width: 100%; max-width: 460px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 24px; padding: 36px; backdrop-filter: blur(20px); box-shadow: 0 30px 60px rgba(0,0,0,0.4); text-align: center; }
.crown { font-size: 38px; margin-bottom: 8px; }
h1 { color: white; font-size: 24px; font-weight: 700; }
.sub { color: rgba(255,255,255,0.5); font-size: 13px; margin: 8px 0 24px; }
.toggle { display: inline-flex; background: rgba(255,255,255,0.05); border-radius: 999px; padding: 4px; margin-bottom: 24px; }
.toggle button { border: none; background: transparent; color: rgba(255,255,255,0.55); padding: 9px 20px; border-radius: 999px; font-size: 13px; font-weight: 600; cursor: pointer; display: flex; align-items: center; gap: 6px; }
.toggle button.active { background: linear-gradient(135deg, #eab308, #f59e0b); color: #1a1a1a; }
.save { background: rgba(34,197,94,0.2); color: #4ade80; font-size: 10px; padding: 2px 6px; border-radius: 999px; font-weight: 700; }
.plans { display: flex; flex-direction: column; gap: 12px; margin-bottom: 24px; }
.plan { position: relative; text-align: left; border: 1.5px solid rgba(255,255,255,0.08); border-radius: 16px; padding: 18px 20px; cursor: pointer; transition: 0.15s; background: rgba(255,255,255,0.02); }
.plan.selected { border-color: #eab308; background: rgba(234,179,8,0.08); }
.popular { position: absolute; top: -10px; right: 16px; background: linear-gradient(135deg, #eab308, #f59e0b); color: #1a1a1a; font-size: 10px; font-weight: 700; padding: 3px 10px; border-radius: 999px; }
.plan-head { display: flex; justify-content: space-between; align-items: baseline; margin-bottom: 10px; }
.plan-name { color: white; font-size: 16px; font-weight: 700; }
.plan-price .amount { color: white; font-size: 20px; font-weight: 700; }
.plan-price .period { color: rgba(255,255,255,0.4); font-size: 12px; margin-left: 2px; }
.amount.hidden { display: none; }
.plan ul { list-style: none; display: flex; flex-direction: column; gap: 6px; }
.plan li { color: rgba(255,255,255,0.6); font-size: 13px; padding-left: 22px; position: relative; }
.plan li::before { content: "✓"; position: absolute; left: 0; color: #eab308; font-weight: 700; }
.cta { width: 100%; padding: 16px; border: none; border-radius: 12px; background: linear-gradient(135deg, #eab308, #f59e0b); color: #1a1a1a; font-size: 15px; font-weight: 700; cursor: pointer; box-shadow: 0 12px 30px rgba(234,179,8,0.3); }

js:
const ctaPrice = document.getElementById('ctaPrice');
let period = 'monthly';

const prices = {
  free: { monthly: 0, yearly: 0, label: 'Ücretsiz' },
  pro: { monthly: 149, yearly: 119, label: 'Pro' },
  enterprise: { monthly: 399, yearly: 319, label: 'Kurumsal' }
};

function setPeriod(p) {
  period = p;
  document.querySelectorAll('.toggle button').forEach(b => b.classList.toggle('active', b.dataset.period === p));
  document.querySelectorAll('.amount.monthly').forEach(el => el.classList.toggle('hidden', p === 'yearly'));
  document.querySelectorAll('.amount.yearly').forEach(el => el.classList.toggle('hidden', p === 'monthly'));
  updateCta();
}

function select(el) {
  document.querySelectorAll('.plan').forEach(p => p.classList.remove('selected'));
  el.classList.add('selected');
  updateCta();
}

function updateCta() {
  const selected = document.querySelector('.plan.selected');
  const planKey = selected.dataset.plan;
  const price = prices[planKey][period];
  ctaPrice.textContent = price === 0 ? 'Ücretsiz Devam Et' : `₺${price}/ay`;
}

function upgrade() {
  const selected = document.querySelector('.plan.selected');
  alert(`${prices[selected.dataset.plan].label} planına geçiş yapılıyor...`);
}
